from math import comb
from fractions import Fraction

line = input().split()
N = int(line[0])
P_str = line[1]
P = float(P_str)

def prob(K, N):
    total = comb(N, 3)
    result = 0.0
    for s in range(4):
        if s > K or (3-s) > (N-K):
            continue
        ways = comb(K, s) * comb(N-K, 3-s)
        if s == 0:
            ps = 0.0
        elif s == 1:
            ps = 0.5
        else:
            ps = 1.0
        result += ways * ps
    return result / total

for K in range(0, N+1):
    if prob(K, N) >= P - 1e-9:
        print(K)
        break
